module llq (clk, d, q);
  parameter WD = 8;
  input clk;
  input [WD-1:0] d;
  output [WD-1:0] q;
  reg [WD-1:0] qin;
  always @(clk or d)
    if (clk == 1'b0)
      qin <= d;
  assign q = qin;
endmodule

llq #(128) dp_ff_en_vld (.clk(clk), .d(flop_en_vld), .q(ff_en_vld));
assign gclk_vld = {128{clk}} & ff_en_vld;
ffq #(1) ff_entry_dvld_0 (.clk(gclk_vld[0]), .d(dvld[0]), .q(entry_vld[0]));

module ffq (clk, d, q);
  parameter WD = 8;
  input clk;
  input [WD-1:0] d;
  output [WD-1:0] q;
  reg [WD-1:0] qin;
  always @(posedge clk)
    qin <= d;
  assign q = qin;
endmodule
// Usage: ffq #(1) ff_entry_dvld_0 (.clk(gclk_vld[0]), .d(dvld[0]), .q(entry_vld[0]));
